import Card from "@/components/Card";

export default function HomePage() {
  const posts = [
    {
      id: 1,
      title: "Exploring Node.js for Beginners",
      content:
        "Learn the basics of Node.js and build simple APIs using Express.",
      imageUrl: "https://images.unsplash.com/photo-1515879218367-8466d910aaa4",
      categories: ["Programming", "Node.js", "Backend"],
      status: "approved",
    },
    {
      id: 2,
      title: "Understanding Mongoose Population",
      content: "How Mongoose populate works for referencing other collections.",
      imageUrl: "https://images.unsplash.com/photo-1555066931-4365d14bab8c",
      categories: ["MongoDB", "Database"],
      status: "pending",
    },
    {
      id: 3,
      title: "Tailwind CSS vs Bootstrap",
      content: "We compare Tailwind CSS and Bootstrap for frontend developers.",
      imageUrl: "https://images.unsplash.com/photo-1556742400-b5b7c5121f5f",
      categories: ["Frontend", "CSS", "UI Design"],
      status: "approved",
    },
  ];

  return (
    <main className="min-h-screen bg-gray-100 py-10 px-6">
      <h1 className="text-3xl font-bold text-center mb-8">Latest Posts</h1>
      <div className="grid gap-6 sm:grid-cols-2 lg:grid-cols-3 max-w-6xl mx-auto">
        {posts.map((post) => (
          <Card key={post.id} post={post} />
        ))}
      </div>
    </main>
  );
}
